// ════════════════════════════════════════════════════════
// TOOL: GERENCIAR SESSÃO DE AGENDAMENTO
// Ações: 'ler', 'atualizar', 'limpar'
// Mantém o cache de sessão com TTL de 2h
// ════════════════════════════════════════════════════════

const input = $input.item.json;
const query = input.query || '';
const organizacaoId = input.organizacao_id || input.organizacaoId;
const remoteJid = input.remote_jid || input.remetente_numero || '';
const instanceName = input.instance_name || '';

// Determinar ação
let acao = input.acao || 'ler';
if (query) {
  const qLower = query.toLowerCase();
  if (qLower.includes('limpar') || qLower.includes('cancelar') || qLower.includes('resetar')) {
    acao = 'limpar';
  } else if (qLower.includes('atualizar') || qLower.includes('salvar') || qLower.includes('update')) {
    acao = 'atualizar';
  } else {
    acao = 'ler';
  }
}

// Dados da sessão para atualizar
const sessionData = input.session_data || input.sessionData || null;
const passoAtual = input.passo_atual || input.passoAtual || null;

if (!remoteJid) {
  return [{ json: { error: true, message: 'remote_jid não informado.' } }];
}
if (!instanceName) {
  return [{ json: { error: true, message: 'instance_name não informado.' } }];
}

return [{
  json: {
    acao: acao,
    remote_jid: remoteJid,
    instance_name: instanceName,
    organizacao_id: organizacaoId,
    session_data: sessionData,
    passo_atual: passoAtual
  }
}];

// Formatar resposta de leitura
const resultado = $input.item.json;

if (resultado && resultado.session_data) {
  const sessionData = typeof resultado.session_data === 'string'
    ? JSON.parse(resultado.session_data)
    : resultado.session_data;

  return [{
    json: {
      response: JSON.stringify({
        sessao_ativa: true,
        passo_atual: resultado.passo_atual,
        dados: sessionData,
        ultima_atualizacao: resultado.updated_at,
        expira_em: resultado.expires_at
      })
    }
  }];
}

return [{
  json: {
    response: JSON.stringify({
      sessao_ativa: false,
      passo_atual: 1,
      dados: {},
      mensagem: 'Nenhuma sessão de agendamento ativa. Iniciando novo processo.'
    })
  }
}];

return [{
  json: {
    response: JSON.stringify({
      sucesso: true,
      mensagem: 'Sessão de agendamento atualizada.',
      passo_atual: $('Extrair Parâmetros').item.json.passo_atual || 1
    })
  }
}];

return [{
  json: {
    response: JSON.stringify({
      sucesso: true,
      mensagem: 'Sessão de agendamento limpa. Pode iniciar novo agendamento.'
    })
  }
}];
